insert into comments (id,model_id,source,comment_text,comment_date) values ('Amazon_22_hm6eyex',22,'Amazon','"The battery life on this phone is an absolute beast, and the massive 120Hz screen is incredible for watching videos. However, the 64GB storage fills up almost instantly with Android 16 system files, and the 15W charging takes nearly 3 hours. It''s a fantastic, future-proof budget 5G phone for casual use, but you will definitely need to buy a MicroSD card for extra space."',NULL) on conflict (id) do nothing;
insert into comments (id,model_id,source,comment_text,comment_date) values ('Flipkart_22_hpan6g1',22,'Flipkart','"Awesome"',NULL) on conflict (id) do nothing;
insert into comments (id,model_id,source,comment_text,comment_date) values ('Amazon_22_h1nk48ld',22,'Amazon','"Cons: 4gb ram sucks. The second you put any app like youtube, Amazon, Chrome or any other significant app in the background, system closes that app. The app restarts upon opening again. It''s impossible to write OTP in any app, since you have to minimize the app to open the msg app to see OTP. And when you get back to the app to write otp, the app restarts. Out of 4gb ram only 1.5gb ram is accessible. 6300mah feels average (I have installed 2 Sims and use it under 5g). It barely lasts one day. Only buy this phone for calls and watching YouTube or if you want cheapest 5g phone. It costed me 11k with all the discounts. Pros: Large screen. Battery management app is very effective. 4 years OS updates. Honestly nothing else."',NULL) on conflict (id) do nothing;
insert into comments (id,model_id,source,comment_text,comment_date) values ('Flipkart_22_h18idcm2',22,'Flipkart','"All things are good except the charge it is not working I am using a different charger to charge"',NULL) on conflict (id) do nothing;
insert into comments (id,model_id,source,comment_text,comment_date) values ('Amazon_22_h1u0rz93',22,'Amazon','"The massive 6,300mAh battery provides incredible two-day endurance, making it perfect for long trips. Its huge 6.9-inch 120Hz display offers a smooth and immersive viewing experience for movies and videos. The Wet Touch 2.0 technology is a game-changer, allowing for easy navigation even with damp fingers. With a promise of 6 years of security updates, it offers the best long-term value in its price segment. The 5G connectivity and HyperOS 3.0 deliver a modern, snappy performance for all daily essential apps."',NULL) on conflict (id) do nothing;
insert into comments (id,model_id,source,comment_text,comment_date) values ('Flipkart_22_hxj715r',22,'Flipkart','"Need to be camera improve very bad photos"',NULL) on conflict (id) do nothing;
insert into comments (id,model_id,source,comment_text,comment_date) values ('Amazon_22_h1bm3puk',22,'Amazon','"I ordered this phone for my Mom on mother''s day, and my Mom is really happy to use this phone. Amazon delivery was pretty good and was on time. About this phone, REDMI A7 Pro 5G is the best in the segment, but personally I found this phone is little slow, and the charger of 33W doesn''t support fast charging. It takes long time to reach 100%, and I found some body heating issues. Rest the phone is excellent. Check some better options if you want to buy in this range."',NULL) on conflict (id) do nothing;
insert into comments (id,model_id,source,comment_text,comment_date) values ('Flipkart_22_hisgplz',22,'Flipkart','"Amazing"',NULL) on conflict (id) do nothing;
insert into comments (id,model_id,source,comment_text,comment_date) values ('Amazon_22_h1eq93aj',22,'Amazon','"The worst phone I bought ever. To be honest, I wouldn''t even give it a single star if that were an option, but since one star is the minimum required to post a review, I am forced to give it that. This phone has been a total nightmare to use. It is riddled with constant glitches that make the overall experience extremely frustrating. The biggest issue is the aggressive app refreshing; every time I switch between apps, they restart or refresh immediately. Multitasking is impossible, and the phone struggles with even the most basic tasks. It has terrible hanging issues that make the device completely unresponsive during normal use. The constant glitches and app refreshing are so frustrating that even basic multitasking is impossible. There is absolutely no point in buying this device. It is a complete waste of money and I highly recommend staying away from it. Don''t make the same mistake I did!"',NULL) on conflict (id) do nothing;
