insert into comments (id,model_id,source,comment_text,comment_date) values ('Amazon_22_h3upmfh',22,'Amazon','"After a month of use, a budget friendly phone, ideal for 50+ age group. Build quality 4⭐, sound quality 4⭐, network connection 5⭐, display 5⭐, processor 4⭐, battery charging 20 to 100% takes two hours 4.5⭐, video rendering 5⭐, voice call & video call 4⭐, games like candy crush, rail rush, subway surfers & temple run 5⭐. If they can provide upcoming 4 OS it would be better. Little bit of heating when using camera. Default settings should be modified to make it easier to use."',NULL) on conflict (id) do nothing;
