insert into comments (id,model_id,source,comment_text,comment_date) values ('Amazon_20_hjv7r9f',20,'Amazon','"I purchased it on 3rd May 2026 when I saw that it had a 10-day return policy from the seller Gold-Enterprise. After receiving the phone, I noticed that it started overheating. It idles at 35–36 degrees and goes above 40 degrees with minimal YouTube usage. When I contacted Amazon support for a return on the 8th day, they denied any return policy even after I shared screenshots showing the 10-day return policy at the time of purchase. One of the supervisors was extremely rude and disconnected the call. If you see a return policy mentioned for an electronics product, don''t assume it will be honored. Never buying from Amazon again."',NULL) on conflict (id) do nothing;
